#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>
#include <assert.h>

#define MAX 11

typedef struct {
    char **strings;
    int size;
    int capacity;
} AnagramGroup;

typedef struct Node {
    char *key;
    AnagramGroup group;
    struct Node *next;
} HashNode;

typedef struct {
    HashNode **table;
    int size;
} HashMap;

unsigned long hash(const char *str) {
    unsigned long hash = 5381;
    int c;
    while ((c = *str++)) {
        hash = ((hash << 5) + hash) + c;  // hash * 33 + c
    }
    return hash;
}

HashMap* createHashMap(int size) {
    HashMap *map = (HashMap *)malloc(sizeof(HashMap));
    map->table = (HashNode **)calloc(size, sizeof(HashNode *));
    map->size = size;
    return map;
}

void insertHashMap(HashMap *map, const char *key, const char *originalStr) {
    unsigned long idx = hash(key) % map->size;
    HashNode *node = map->table[idx];

    while (node) {
        if (strcmp(node->key, key) == 0) {
            if (node->group.size == node->group.capacity) {
                node->group.capacity *= 2;
                node->group.strings = (char **)realloc(node->group.strings, node->group.capacity * sizeof(char *));
            }
            node->group.strings[node->group.size++] = strdup(originalStr);
            return;
        }
        node = node->next;
    }

    node = (HashNode *)malloc(sizeof(HashNode));
    node->key = strdup(key);
    node->group.strings = (char **)malloc(10 * sizeof(char *));
    node->group.capacity = 10;
    node->group.size = 1;
    node->group.strings[0] = strdup(originalStr);
    node->next = map->table[idx];
    map->table[idx] = node;
}

AnagramGroup* getAnagramGroups(HashMap *map, int *groupCount) {
    int count = 0;
    for (int i = 0; i < map->size; i++) {
        HashNode *node = map->table[i];
        while (node) {
            count++;
            node = node->next;
        }
    }

    AnagramGroup *groups = (AnagramGroup *)malloc(count * sizeof(AnagramGroup));
    int idx = 0;
    for (int i = 0; i < map->size; i++) {
        HashNode *node = map->table[i];
        while (node) {
            groups[idx++] = node->group;
            node = node->next;
        }
    }

    *groupCount = count;
    return groups;
}

void freeHashMap(HashMap *map) {
    for (int i = 0; i < map->size; i++) {
        HashNode *node = map->table[i];
        while (node) {
            free(node->key);
            for (int j = 0; j < node->group.size; j++) {
                free(node->group.strings[j]);
            }
            free(node->group.strings);
            HashNode *temp = node;
            node = node->next;
            free(temp);
        }
    }
    free(map->table);
    free(map);
}

void sortString(char *str) {
    int len = strlen(str);
    qsort(str, len, sizeof(char), (int (*)(const void *, const void *))strcmp);
}

int compareStrings(const void *a, const void *b) {
    return strcmp(*(const char **)a, *(const char **)b);
}

bool checkAnagram(char **group, int size) {
    char sorted[MAX];
    sortString(strcpy(sorted, group[0]));
    for (int i = 1; i < size; i++) {
        char temp[MAX];
        sortString(strcpy(temp, group[i]));
        if (strcmp(sorted, temp) != 0) {
            return false;
        }
    }
    return true;
}

int main() {
    int n;
    scanf("%d", &n);
    assert(1 <= n && n <= 100000);

    char **strings = (char **)malloc(n * sizeof(char *));
    for (int i = 0; i < n; i++) {
        strings[i] = (char *)malloc(MAX * sizeof(char));
        scanf("%s", strings[i]);
        int sz = strlen(strings[i]);
        assert(sz >= 1 && sz <= 10);
    }

    HashMap *map = createHashMap(n);

    // Group the anagrams using a hash map
    for (int i = 0; i < n; i++) {
        char sorted[MAX];
        strcpy(sorted, strings[i]);
        sortString(sorted);
        insertHashMap(map, sorted, strings[i]);
    }

    // Collect anagram groups
    int groupCount;
    AnagramGroup *anagramGroups = getAnagramGroups(map, &groupCount);

    char **anagramGroupsStrings = (char **)malloc(n * sizeof(char *));
    int idx = 0;
    for (int i = 0; i < groupCount; i++) {
        assert(checkAnagram(anagramGroups[i].strings, anagramGroups[i].size) == true);
        for (int j = 0; j < anagramGroups[i].size; j++) {
            anagramGroupsStrings[idx++] = anagramGroups[i].strings[j];
        }
    }

    qsort(strings, n, sizeof(char *), compareStrings);
    qsort(anagramGroupsStrings, n, sizeof(char *), compareStrings);

    for (int i = 0; i < n; i++) {
        assert(strcmp(strings[i], anagramGroupsStrings[i]) == 0);
    }

    printf("Nicely Grouped!\n");

    // Free allocated memory
    for (int i = 0; i < n; i++) {
        free(strings[i]);
    }
    free(strings);
    free(anagramGroupsStrings);
    freeHashMap(map);

    return 0;
}

