const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function groupAnagrams(strings) {
    let map = {};
    for (let str of strings) {
        let key = str.split('').sort().join('');
        if (!map[key]) {
            map[key] = [];
        }
        map[key].push(str);
    }
    return Object.values(map);
}

function checkAnagram(group) {
    let sortedForm = group[0].split('').sort().join('');
    return group.every(str => str.split('').sort().join('') === sortedForm);
}

let n = parseInt(lines[idx++]);
let strings = lines.slice(idx, idx + n);
idx += n;

if (n < 1 || n > 100000) throw new Error('Invalid n');
for (let str of strings) {
    if (str.length < 1 || str.length > 10) throw new Error('Invalid string length');
}

let anagramGroups = groupAnagrams(strings);
let anagramGroupsStrings = [];
for (let group of anagramGroups) {
    if (!checkAnagram(group)) throw new Error('Invalid anagram group');
    anagramGroupsStrings.push(...group);
}

strings.sort();
anagramGroupsStrings.sort();

if (JSON.stringify(strings) !== JSON.stringify(anagramGroupsStrings)) throw new Error('Strings do not match');

